import React, { useState } from 'react';
import DiceRoll from 'react-dice-roll';

function App() {
  const [player, setPlayer] = useState('');
  const [position, setPosition] = useState(0);
  const [turn, setTurn] = useState(1);
  const [rotation, setRotation] = useState(0); // board rotation degrees: 0, 90, 180, 270

  const [diceRolls, setDiceRolls] = useState([]); // to store dice values until both rolled

  // Cards setup
  const cardImages = [
    '1_bereshitA.png',
    '1B_bereshitB.png',
    'possible restyle.png',
  ];
  const [currentCardIndex, setCurrentCardIndex] = useState(0);

  const handleRollDone = (value) => {
    setDiceRolls((prev) => {
      const newRolls = [...prev, value];
      if (newRolls.length === 2) {
        const total = newRolls[0] + newRolls[1];
        setPosition((pos) => (pos + total) % 20);
        setTurn((t) => t + 1);
        return [];
      }
      return newRolls;
    });
  };

  const rotateBoard = () => {
    setRotation((prev) => (prev + 90) % 360);
  };

  const prevCard = () => {
    setCurrentCardIndex((prev) =>
      prev === 0 ? cardImages.length - 1 : prev - 1
    );
  };

  const nextCard = () => {
    setCurrentCardIndex((prev) =>
      prev === cardImages.length - 1 ? 0 : prev + 1
    );
  };

  return (
    <div style={{ padding: 20, fontFamily: 'Arial' }}>
      <h1>Monopoly Starter Game</h1>

      <div
        style={{
          maxWidth: '900px',
          marginBottom: '20px',
          border: '2px solid #000',
          display: 'inline-block',
          transform: `rotate(${rotation}deg)`,
          transition: 'transform 0.5s ease',
        }}
      >
        <img
          src={`${process.env.PUBLIC_URL}/torahpoly_board.png`}
          alt="Monopoly Board"
          style={{ maxWidth: '100%', height: 'auto', display: 'block' }}
        />
      </div>

      <div>
        <button
          onClick={rotateBoard}
          style={{
            padding: '10px 20px',
            fontSize: '16px',
            marginBottom: '20px',
            cursor: 'pointer',
          }}
        >
          Rotate Board
        </button>
      </div>

      <input
        placeholder="Enter your player name"
        value={player}
        onChange={(e) => setPlayer(e.target.value)}
        style={{
          padding: '8px',
          fontSize: '16px',
          width: '100%',
          maxWidth: '300px',
          marginBottom: '10px',
        }}
      />

      <p>Turn: {turn}</p>
      <p>Player: {player || 'No player yet'}</p>
      <p>Position: {position}</p>

      <div style={{ display: 'flex', gap: '20px', marginBottom: '20px' }}>
        <DiceRoll onRollDone={handleRollDone} size={100} />
        <DiceRoll onRollDone={handleRollDone} size={100} />
      </div>

      {/* Cards Section */}
      <div
        style={{
          marginTop: '40px',
          borderTop: '2px solid #000',
          paddingTop: '20px',
          maxWidth: '350px',
          marginLeft: 'auto',
          marginRight: 'auto',
          textAlign: 'center',
        }}
      >
        <h2>Question Card</h2>
        <img
          src={`${process.env.PUBLIC_URL}/${cardImages[currentCardIndex]}`}
          alt={`Question Card ${currentCardIndex + 1}`}
          style={{ width: '300px', border: '2px solid black' }}
        />
        <div style={{ marginTop: '10px' }}>
          <button
            onClick={prevCard}
            style={{ marginRight: '10px', padding: '8px 12px', cursor: 'pointer' }}
          >
            Previous Card
          </button>
          <button
            onClick={nextCard}
            style={{ padding: '8px 12px', cursor: 'pointer' }}
          >
            Next Card
          </button>
        </div>
      </div>
    </div>
  );
}

export default App;
